// Generuj kombinacje query + city z Config
const config = $input.first().json;
const queries = config.SEARCH_QUERIES || [];
const results = [];

for (const q of queries) {
  for (const city of q.cities) {
    results.push({
      json: {
        search_query: `${q.query} in ${city}, Netherlands`,
        query_type: q.query,
        city: city,
        country: 'Netherlands'
      }
    });
  }
}

// Losuj max 20 kombinacji dziennie (żeby nie przekroczyć limitów)
const shuffled = results.sort(() => Math.random() - 0.5);
return shuffled.slice(0, 20);

// Parsuj wyniki SerpAPI Google Maps
const input = $input.first().json;
const results = input.local_results || input.place_results || [];
const city = $('🔀 Generate Search Queries').first().json.city;
const queryType = $('🔀 Generate Search Queries').first().json.query_type;

const leads = [];

for (const place of results) {
  // FILTR: musi mieć telefon
  if (!place.phone) continue;

  // FILTR: pomiń jeśli brak adresu
  if (!place.address) continue;

  // FILTR: pomiń eenmanszaken (rating count < 5 = prawdopodobnie bardzo mały)
  // Ten filtr jest miękki — możesz go wyłączyć

  // FILTR: pomiń sieci korporacyjne (HQ)
  const skipNames = ['albert heijn', 'ikea', 'jumbo', 'lidl', 'aldi', 'action', 'hema', 'kruidvat', 'blokker'];
  const nameLower = (place.title || '').toLowerCase();
  const isCorpHQ = skipNames.some(s => nameLower.includes(s));
  if (isCorpHQ) continue;

  // Określ sektor na podstawie query type
  let sektor = 'onbekend';
  if (queryType.includes('fashion') || queryType.includes('kleding') || queryType.includes('schoen') || queryType.includes('sport')) sektor = 'retail';
  else if (queryType.includes('restaurant') || queryType.includes('horeca') || queryType.includes('hotel')) sektor = 'horeca';
  else if (queryType.includes('warehouse') || queryType.includes('logistics') || queryType.includes('transport')) sektor = 'logistiek';
  else if (queryType.includes('tandarts') || queryType.includes('fysio')) sektor = 'zorg';
  else if (queryType.includes('bouw') || queryType.includes('aannemer')) sektor = 'bouw';
  else if (queryType.includes('franchise') || queryType.includes('supermarket') || queryType.includes('food')) sektor = 'retail';
  else if (queryType.includes('auto') || queryType.includes('garage')) sektor = 'automotive';

  leads.push({
    json: {
      Nazwa_Firmy: place.title || '',
      Adres: place.address || '',
      Miasto: city,
      Telefon: place.phone || '',
      Website: place.website || place.link || '',
      Sektor: sektor,
      Rating: place.rating || '',
      Reviews: place.reviews || '',
      Godziny_Otwarcia: (place.hours || place.operating_hours?.wednesday) || '',
      GPS: place.gps_coordinates ? `${place.gps_coordinates.latitude},${place.gps_coordinates.longitude}` : '',
      Zrodlo: 'google_maps_scraper',
      Data_Scrape: new Date().toISOString().split('T')[0]
    }
  });
}

return leads.length > 0 ? leads : [{ json: { skip: true } }];

// Deduplikacja: sprawdź czy lead już istnieje w Sheets
const newLeads = $('✅ Filter Valid').all();
const existingLeads = $('📥 Get Existing Leads').all();

// Zbuduj set istniejących firm (Nazwa + Miasto)
const existingSet = new Set();
for (const lead of existingLeads) {
  const key = `${(lead.json.Nazwa_Firmy || '').toLowerCase().trim()}|${(lead.json.Miasto || '').toLowerCase().trim()}`;
  existingSet.add(key);
}

// Filtruj duplikaty
const uniqueLeads = [];
const seenInBatch = new Set();

for (const lead of newLeads) {
  const key = `${(lead.json.Nazwa_Firmy || '').toLowerCase().trim()}|${(lead.json.Miasto || '').toLowerCase().trim()}`;

  // Pomiń jeśli już w Sheets
  if (existingSet.has(key)) continue;

  // Pomiń jeśli duplikat w bieżącym batchu
  if (seenInBatch.has(key)) continue;

  seenInBatch.add(key);

  // Generuj ID
  const id = `VTX-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`;

  uniqueLeads.push({
    json: {
      ID: id,
      Nazwa_Firmy: lead.json.Nazwa_Firmy,
      Telefon: lead.json.Telefon,
      Email: '',
      Miasto: lead.json.Miasto,
      Sektor: lead.json.Sektor,
      Status: 'Nieuw',
      Notatki: `Website: ${lead.json.Website || 'brak'} | Rating: ${lead.json.Rating || 'n/a'} (${lead.json.Reviews || '0'} reviews) | Adres: ${lead.json.Adres}`,
      Liczba_Prob: 0,
      Callback_Time: '',
      Data_Ostatniego_Kontaktu: '',
      Zrodlo: lead.json.Zrodlo
    }
  });
}

if (uniqueLeads.length === 0) {
  return [{ json: { no_new_leads: true, message: 'Brak nowych leadów do dodania' } }];
}

return uniqueLeads;

// Podsumowanie scrape'a
const newLeads = $('📤 Write to Sheets').all();
const count = newLeads.length;
const date = new Date().toISOString().split('T')[0];

// Breakdown per sektor
const sektorCount = {};
for (const lead of newLeads) {
  const s = lead.json.Sektor || 'onbekend';
  sektorCount[s] = (sektorCount[s] || 0) + 1;
}

const breakdown = Object.entries(sektorCount)
  .map(([k, v]) => `${k}: ${v}`)
  .join(', ');

// Breakdown per miasto
const cityCount = {};
for (const lead of newLeads) {
  const c = lead.json.Miasto || 'onbekend';
  cityCount[c] = (cityCount[c] || 0) + 1;
}

const cityBreakdown = Object.entries(cityCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([k, v]) => `${k}: ${v}`)
  .join(', ');

return [{
  json: {
    date: date,
    total_new_leads: count,
    sektor_breakdown: breakdown,
    city_breakdown: cityBreakdown,
    message: `🟢 Lead Scraper ${date}: ${count} nieuwe leads toegevoegd. Sectoren: ${breakdown}. Top steden: ${cityBreakdown}.`
  }
}];
